// Get all users
const users = $input.all();

// Filter to only active, non-bot, non-guest users
const filteredUsers = users.filter(item => {
  const user = item.json;

  return (
    !user.deleted &&           // Not deleted
    !user.is_bot &&            // Not a bot
    !user.is_restricted &&     // Not a guest
    user.id !== 'USLACKBOT'    // Not Slackbot itself
  );
});

// Remove duplicates by ID using a Map
const uniqueUsersMap = new Map();

filteredUsers.forEach(item => {
  const userId = item.json.id;
  // Only add if we haven't seen this ID before
  if (!uniqueUsersMap.has(userId)) {
    uniqueUsersMap.set(userId, item);
  }
});

// Convert Map back to array
const uniqueUsers = Array.from(uniqueUsersMap.values());

return uniqueUsers;

// Get channels and users from previous nodes
const channels = $('getChannels').all();
const users = $('realUsers').all();

// Get the user_channel and message from webhook
const webhookData = $('Webhook').first().json.body;
const userChannel = webhookData.user_channel;
const messages = webhookData.message_count;

// Format channels for AI context
const formattedChannels = channels.map(item => ({
  id: item.json.id,
  name: item.json.name,
  is_private: item.json.is_private || false
}));

// Format users for AI context
const formattedUsers = users.map(item => ({
  id: item.json.id,
  name: item.json.real_name || item.json.name,
  display_name: item.json.profile?.display_name || ''
}));

// Return single item with all context for the AI
return [{
  json: {
    timestamp: new Date().toISOString(),
    user_channel: userChannel,
    message_count: messages,  // Pass message through unchanged
    channels: formattedChannels,
    users: formattedUsers,
  }
}];

// Get the AI output string
const outputString = $input.first().json.output;
const parsedOutput = JSON.parse(outputString);
const messageCount = $('agentSetup').first().json.message_count;
const timestamp = $('agentSetup').first().json.timestamp
// Return the complete object
return [{
  json: {
    ...parsedOutput,
    messageCount,
    timestamp
}
}]

const messages = $input.all();

const formatted = messages.map(msg => {
  const channel = msg.json.channel_name;
  const sender = msg.json.user_name;
  const text = msg.json.text;
  return `In ${channel}, ${sender} says: ${text}`;
}).join('. ');

return [{ json: { speech: formatted } }];
